import{_ as i,o as e,c as l,ag as t}from"./chunks/framework.HKmjcgbP.js";const s=JSON.parse('{"title":"Go","description":"","frontmatter":{},"headers":[],"relativePath":"其他/go.md","filePath":"其他/go.md","lastUpdated":1675132199000}'),r={name:"其他/go.md"};function o(n,a,u,p,h,c){return e(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="go" tabindex="-1">Go <a class="header-anchor" href="#go" aria-label="Permalink to &quot;Go&quot;">​</a></h1><h2 id="数据类型" tabindex="-1">数据类型 <a class="header-anchor" href="#数据类型" aria-label="Permalink to &quot;数据类型&quot;">​</a></h2><h3 id="布尔" tabindex="-1">布尔 <a class="header-anchor" href="#布尔" aria-label="Permalink to &quot;布尔&quot;">​</a></h3><h3 id="数字" tabindex="-1">数字 <a class="header-anchor" href="#数字" aria-label="Permalink to &quot;数字&quot;">​</a></h3><h3 id="字符串" tabindex="-1">字符串 <a class="header-anchor" href="#字符串" aria-label="Permalink to &quot;字符串&quot;">​</a></h3><ul><li>Unicode 文本</li></ul><h3 id="派生" tabindex="-1">派生 <a class="header-anchor" href="#派生" aria-label="Permalink to &quot;派生&quot;">​</a></h3><ul><li><p>指针</p><ul><li><p>取地址符是 &amp;</p></li><li><p>var var_name *var-type</p></li><li><ul><li>获取指针所指向的内容</li></ul></li><li><p>指针数组</p><ul><li>存放指针的数组</li></ul></li><li><p>指向指针的指针</p><ul><li>var ptr **int;</li></ul></li></ul></li><li><p>数组</p><ul><li>var variable_name [SIZE] variable_type</li></ul></li><li><p>结构化</p></li><li><p>Channel</p><ul><li>传递数据的一个数据结构</li><li>操作符 &lt;- 用于指定通道的方向，发送或接收</li><li>如果未指定方向，则为双向通道。</li><li>ch := make(chan int)</li></ul></li><li><p>函数</p></li><li><p>切片</p><ul><li><p>对数组的抽象。</p></li><li><p>长度是不固定的</p></li><li><p>var identifier []type</p><ul><li>未指定大小的数组来定义切片</li></ul></li><li><p>make()函数来创建切片:</p><ul><li>make([]T, length, capacity)</li></ul></li><li><p>len() 方法获取长度</p></li><li><p>cap() 可以测量切片最长可以达到多少</p></li><li><p>拷贝切片的 copy 方法</p></li><li><p>切片追加新元素的 append 方法</p></li></ul></li><li><p>接口</p><p>type Phone interface {   call() }</p><p>type NokiaPhone struct { }</p><p>func (nokiaPhone NokiaPhone) call() {   fmt.Println(&quot;I am Nokia, I can call you!&quot;) }</p></li><li><p>Map</p><p>var countryCapitalMap map[string]string /*创建集合 */   countryCapitalMap = make(map[string]string)</p><p>/* map插入key - value对,各个国家对应的首都 */   countryCapitalMap [ &quot;France&quot; ] = &quot;巴黎&quot;   countryCapitalMap [ &quot;Italy&quot; ] = &quot;罗马&quot;   countryCapitalMap [ &quot;Japan&quot; ] = &quot;东京&quot;   countryCapitalMap [ &quot;India &quot; ] = &quot;新德里&quot;</p><ul><li>delete() 函数用于删除集合的元素, 参数为 map 和其对应的 key。</li></ul></li></ul><h3 id="值类型与引用类型" tabindex="-1">值类型与引用类型 <a class="header-anchor" href="#值类型与引用类型" aria-label="Permalink to &quot;值类型与引用类型&quot;">​</a></h3><ul><li><p>基本类型都属于值类型，</p><ul><li>变量直接指向存在内存中的值：</li><li>将 i 的值进行了拷贝</li></ul></li><li><p>引用类型的变量 r1 存储的是 r1 的值所在的内存地址（数字），或内存地址中第一个字所在的位置。</p><ul><li>引用（地址）被复制</li><li>被修改后的内容，会受到影响。</li></ul></li></ul><h2 id="流程控制" tabindex="-1">流程控制 <a class="header-anchor" href="#流程控制" aria-label="Permalink to &quot;流程控制&quot;">​</a></h2><h3 id="条件语句" tabindex="-1">条件语句 <a class="header-anchor" href="#条件语句" aria-label="Permalink to &quot;条件语句&quot;">​</a></h3><ul><li><p>if...else</p></li><li><p>switch</p><p>switch marks {     case 90: grade = &quot;A&quot;     case 80: grade = &quot;B&quot;     case 50,60,70 : grade = &quot;C&quot;     default: grade = &quot;D&quot;     }</p><ul><li>type-switch</li></ul><pre><code>switch x.(type){
    case type:
       statement(s);      
    case type:
       statement(s); 
    /* 你可以定义任意个数的case */
    default: /* 可选 */
       statement(s);
}
</code></pre><ul><li>fallthrough 会强制执行后面的 case 语句</li></ul></li><li><p>select 语句</p><p>select {     case i1 = &lt;-c1:      fmt.Printf(&quot;received &quot;, i1, &quot; from c1\\n&quot;)     case c2 &lt;- i2:      fmt.Printf(&quot;sent &quot;, i2, &quot; to c2\\n&quot;)     case i3, ok := (&lt;-c3):  // same as: i3, ok := &lt;-c3      if ok {       fmt.Printf(&quot;received &quot;, i3, &quot; from c3\\n&quot;)      } else {       fmt.Printf(&quot;c3 is closed\\n&quot;)      }     default:      fmt.Printf(&quot;no communication\\n&quot;)</p><ul><li>循环检测条件</li></ul></li><li><p>没有三目运算符</p></li></ul><h3 id="循环语句" tabindex="-1">循环语句 <a class="header-anchor" href="#循环语句" aria-label="Permalink to &quot;循环语句&quot;">​</a></h3><ul><li><p>for init; condition; post</p></li><li><p>For-each range 循环</p><p>strings := []string{&quot;google&quot;, &quot;runoob&quot;}      for i, s := range strings {         fmt.Println(i, s)      }</p></li><li><p>标号 label 标出想 break 的循环</p></li><li><p>标号 label 标出想 continue 的循环</p></li></ul><h2 id="函数" tabindex="-1">函数 <a class="header-anchor" href="#函数" aria-label="Permalink to &quot;函数&quot;">​</a></h2><p>func function_name( [parameter list] ) [return_types] { 函数体 }</p><h3 id="可以返回多个值" tabindex="-1">可以返回多个值 <a class="header-anchor" href="#可以返回多个值" aria-label="Permalink to &quot;可以返回多个值&quot;">​</a></h3><h3 id="闭包" tabindex="-1">闭包 <a class="header-anchor" href="#闭包" aria-label="Permalink to &quot;闭包&quot;">​</a></h3><p>func getSequence() func() int {   i:=0   return func() int {     i+=1    return i     } }</p><h3 id="方法" tabindex="-1">方法 <a class="header-anchor" href="#方法" aria-label="Permalink to &quot;方法&quot;">​</a></h3><p>//该 method 属于 Circle 类型对象中的方法 func (c Circle) getArea() float64 {   <a href="//c.radius" target="_blank" rel="noreferrer">//c.radius</a> 即为 Circle 类型对象中的属性   return 3.14 * c.radius * c.radius }</p><h2 id="结构" tabindex="-1">结构 <a class="header-anchor" href="#结构" aria-label="Permalink to &quot;结构&quot;">​</a></h2><p>package main</p><p>import &quot;fmt&quot;</p><p>func main() {   /* 这是我的第一个简单的程序 */   fmt.Println(&quot;Hello, World!&quot;) }</p><h3 id="包声明" tabindex="-1">包声明 <a class="header-anchor" href="#包声明" aria-label="Permalink to &quot;包声明&quot;">​</a></h3><h3 id="引入包" tabindex="-1">引入包 <a class="header-anchor" href="#引入包" aria-label="Permalink to &quot;引入包&quot;">​</a></h3><h3 id="函数-1" tabindex="-1">函数 <a class="header-anchor" href="#函数-1" aria-label="Permalink to &quot;函数&quot;">​</a></h3><h3 id="变量" tabindex="-1">变量 <a class="header-anchor" href="#变量" aria-label="Permalink to &quot;变量&quot;">​</a></h3><ul><li><p>var identifier type</p></li><li><p>如果没有初始化，则变量默认为零值。</p></li><li><p>根据值自行判定变量类型。</p></li><li><p>:=</p><ul><li>声明新的变量</li><li>函数内部</li></ul></li><li><p>值必须被使用</p></li><li><p>_ 也被用于抛弃值</p></li></ul><h3 id="语句-表达式" tabindex="-1">语句 &amp; 表达式 <a class="header-anchor" href="#语句-表达式" aria-label="Permalink to &quot;语句 &amp; 表达式&quot;">​</a></h3><h3 id="注释" tabindex="-1">注释 <a class="header-anchor" href="#注释" aria-label="Permalink to &quot;注释&quot;">​</a></h3><h3 id="常量" tabindex="-1">常量 <a class="header-anchor" href="#常量" aria-label="Permalink to &quot;常量&quot;">​</a></h3><ul><li><p>const identifier [type] = value</p></li><li><p>iota，特殊常量</p><p>const (    i=1&lt;&lt;iota   j=3&lt;&lt;iota   k   l ) i= 1 j= 6 k= 12 l= 24</p><ul><li>在 const关键字出现时将被重置为 0</li><li>const 中每新增一行常量声明将使 iota 计数一次</li></ul></li></ul><h2 id="结构体" tabindex="-1">结构体 <a class="header-anchor" href="#结构体" aria-label="Permalink to &quot;结构体&quot;">​</a></h2><p>type Books struct {   title string   author string   subject string   book_id int }</p><h2 id="错误处理" tabindex="-1">错误处理 <a class="header-anchor" href="#错误处理" aria-label="Permalink to &quot;错误处理&quot;">​</a></h2><p>// 实现 <code>error</code> 接口 func (de *DivideError) Error() string {   strFormat := <code>  Cannot proceed, the divider is zero.   dividee: %d   divider: 0</code>    return fmt.Sprintf(strFormat, de.dividee) }</p><h3 id="type-error-interface" tabindex="-1">type error interface { <a class="header-anchor" href="#type-error-interface" aria-label="Permalink to &quot;type error interface {&quot;">​</a></h3><pre><code>Error() string
</code></pre><p>}</p><h2 id="并发" tabindex="-1">并发 <a class="header-anchor" href="#并发" aria-label="Permalink to &quot;并发&quot;">​</a></h2><h3 id="go-函数名-参数列表" tabindex="-1">go 函数名( 参数列表 ) <a class="header-anchor" href="#go-函数名-参数列表" aria-label="Permalink to &quot;go 函数名( 参数列表 )&quot;">​</a></h3><h3 id="goroutine-是轻量级线程-goroutine-的调度是由-golang-运行时进行管理的。" tabindex="-1">goroutine 是轻量级线程，goroutine 的调度是由 Golang 运行时进行管理的。 <a class="header-anchor" href="#goroutine-是轻量级线程-goroutine-的调度是由-golang-运行时进行管理的。" aria-label="Permalink to &quot;goroutine 是轻量级线程，goroutine 的调度是由 Golang 运行时进行管理的。&quot;">​</a></h3><p><em>XMind: ZEN - Trial Version</em></p>`,46)])])}const q=i(r,[["render",o]]);export{s as __pageData,q as default};
